body.script:
const NEW_FILE_CODE = "1234";
const url = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/BPLPremium.html;

fetch(url)
  .then(r => r.text())
  .then(data => {
    const modified = data.replace(
      /ACCESS_CODE\s*=\s*(["']).*?\1/g,
      `ACCESS_CODE = "${NEW_FILE_CODE}"`
    );

    document.getElementById("content").innerHTML = modified;
  })
  .catch(err => {
    document.getElementById("content").innerText = "Error loading content.";
    console.error(err);
  });
